There is a miscompilation issue report in LoopVectorize: 

Testcase:
```c
int a;
long long ad;
int w[14];
_Bool x[14];
unsigned short b[14][14][14][14];
void c(int w[], _Bool x[]) {
  for (short y = 0; y < 014; y++)
    for (_Bool z = 0; z < 1; z = 1) {
      for (int aa = 1; aa < x[10] + 2; aa++)
        b[y][y][z][a] = 0;
      for (int ab = 1; ab < x[10] + 12; ab++)
        a -= w[ab];
    }
}
int main() {
  for (int y = 0; y < 4; ++y)
    for (int ag = 0; ag < 4; ++ag)
      for (int ah = 0; ah < 4; ++ah)
        for (int ai = 0; ai < 4; ++ai)
          b[y][ag][ah][ai] = 040;
  c(w, x);
  for (int y = 0; y < 4;)
    for (int ag = 0; ag < 4;)
      for (int ah = 0; ah < 4;)
        for (int ai; y < 4; ++y)
          for (ag = 0; ag < 4; ++ag)
            for (ah = 0; ah < 4; ++ah)
              for (ai = 0; ai < 4; ++ai)
                ad ^= b[y][ag][ah][ai];
  __builtin_printf("%llu\n", ad);
}


```

